mapper.select:
SELECT T.PARAM_NO, T.PARAM_ITEM_NO, T.DEFAULT_VAL, PI.PARAM_ITEM_ID, SY.CONTENT AS PARAM_NAME FROM PA_PARAM_ITEM_PARAM T, PA_PARAM_ITEM PI, SY_GLOBAL_NAME SY WHERE T.PARAM_ITEM_NO = PI.PARAM_ITEM_NO AND T.PARAM_ITEM_NO = SY.NO AND SY.LANGUAGE = #{lang, jdbcType=VARCHAR} AND PI.ACTIVITY = 1
AND PI.ITEM_TYPE = #{itemType, jdbcType=VARCHAR}
AND T.ACTIVITY = '1' AND T.CPNY_ID = #{cpnyId, jdbcType=VARCHAR} ORDER BY PI.ORDER_NO

mapper.delete:
UPDATE PA_PARAM_DATA
   SET ACTIVITY = 0,
       UPDATED_BY  = #{adminID, jdbcType=VARCHAR},
       UPDATE_DATE = SYSDATE,
       UPDATED_IP  = #{adminIP, jdbcType=VARCHAR}
 WHERE PARAM_DATA_NO = #{paramDataNo, jdbcType=NUMERIC}

DELETE FROM PA_PARAM_DATA_TEMP
 WHERE UPLOAD_BY = #{adminID, jdbcType=VARCHAR}
   AND CPNY_ID   = #{cpnyId,  jdbcType=VARCHAR}

